<?php namespace App\Models; use Illuminate\Database\Eloquent\Model; class PaymentWebhookEvent extends Model{protected $fillable=['provider','provider_event_id','event_type','payload_hash','status','related_payment_record_id','received_at','processed_at','failure_reason','metadata'];protected function casts():array{return ['received_at'=>'datetime','processed_at'=>'datetime','metadata'=>'array'];}public function paymentRecord(){return $this->belongsTo(PaymentRecord::class,'related_payment_record_id');}}
